template <typename T>
T** allocate2DMatrix(int rows, int cols) {
    if (rows <= 0 || cols <= 0) {
        std::cerr << "Error: Rows and columns must be positive integers." << std::endl;
        exit(1);
    }

    // Calculate total size
    size_t size = rows * cols * sizeof(T);

    // Allocate memory for the matrix
    T** matrix = (T**)malloc(rows * sizeof(T*));
    if (!matrix) {
        std::cerr << "Error: Memory allocation failed." << std::endl;
        exit(1);
    }

    // Allocate memory for each row
    for (int i = 0; i < rows; ++i) {
        matrix[i] = (T*)malloc(cols * sizeof(T));
        if (!matrix[i]) {
            std::cerr << "Error: Memory allocation failed." << std::endl;
            exit(1);
        }
    }

    return matrix;
}

